31	namespace slang_frontend {
32	
33	void import_blackboxes_from_rtlil(
34			slang::SourceManager &mgr, ast::Compilation &target, RTLIL::Design *source)
35	{
36		using namespace slang;
37		using namespace slang::ast;
38		using namespace slang::syntax;
39		using namespace slang::parsing;
40	
41		BumpAllocator alloc;
42	
43		auto token = [&](TokenKind kind, std::string text = "", bool space = false, bool eol = false) {
44			char *ptr = (char *)alloc.allocate(text.size(), 1);
45			memcpy(ptr, text.data(), text.size());
46	
47			SmallVector<Trivia, 2> trivia;
48			if (space)
49				trivia.push_back(Trivia(TriviaKind::Whitespace, " "sv));
50			if (eol)
51				trivia.push_back(Trivia(TriviaKind::EndOfLine, "\n"sv));
52	
53			return Token(target, kind, trivia.copy(target), std::string_view{ptr, text.size()},
54					SourceLocation::NoLocation);
55		};
56	
57		auto integer_literal = [&](int value) {
58			std::string text = std::to_string(value);
59			char *ptr = (char *)alloc.allocate(text.size(), 1);
60			memcpy(ptr, text.data(), text.size());
61	
62			return Token(target, TokenKind::IntegerLiteral, {}, std::string_view{ptr, text.size()},
63					SourceLocation::NoLocation, SVInt(value));
64		};
65	
66		SmallVector<MemberSyntax *, 16> decls;
67	
68		for (auto module : source->modules()) {
69			std::string unescaped_id = RTLIL::unescape_id(module->name);
70	
71			if (target.tryGetDefinition(unescaped_id, target.getRootNoFinalize()).definition)
72				continue;
73	
74			SmallVector<TokenOrSyntax, 16> port_list;
75	
76			for (auto portname : module->ports) {
77				RTLIL::Wire *port = module->wire(portname);
78	
79				TokenKind direction;
80				if (port->port_input && !port->port_output)
81					direction = TokenKind::InputKeyword;
82				else if (port->port_output && !port->port_input)
83					direction = TokenKind::OutputKeyword;
84				else
85					direction = TokenKind::InOutKeyword;
86	
87				SmallVector<VariableDimensionSyntax *, 2> dims;
88				dims.push_back(alloc.emplace<VariableDimensionSyntax>(
89						token(TokenKind::OpenBracket, "", true),
90						alloc.emplace<RangeDimensionSpecifierSyntax>(*alloc.emplace<RangeSelectSyntax>(
91								SyntaxKind::SimpleRangeSelect,
92								*alloc.emplace<LiteralExpressionSyntax>(
93										SyntaxKind::IntegerLiteralExpression,
94										integer_literal(port->width - 1)),
95								Token(target, TokenKind::Colon, {}, "", SourceLocation::NoLocation),
96								*alloc.emplace<LiteralExpressionSyntax>(
97										SyntaxKind::IntegerLiteralExpression, integer_literal(0)))),
98						Token(target, TokenKind::CloseBracket, {}, "", SourceLocation::NoLocation)));
99	
100				port_list.push_back(alloc.emplace<ImplicitAnsiPortSyntax>(
101						*alloc.emplace<SyntaxList<AttributeInstanceSyntax>>(alloc, std::span<const TokenOrSyntax>{}),
102						*alloc.emplace<VariablePortHeaderSyntax>(Token(),
103								token(direction, "", false, true), Token(),
104								*alloc.emplace<ImplicitTypeSyntax>(Token(),
105										*alloc.emplace<SyntaxList<VariableDimensionSyntax>>(
106												alloc, dims.copy(target)),
107										Token())),
108						*alloc.emplace<DeclaratorSyntax>(
109								token(TokenKind::Identifier, RTLIL::escape_id(port->name.str()), true),
110								*alloc.emplace<SyntaxList<VariableDimensionSyntax>>(alloc, std::span<const TokenOrSyntax>{}),
111								nullptr)));
112				port_list.push_back(token(TokenKind::Comma));
113			}
114			if (!port_list.empty())
115				port_list.pop_back();
116	
117			auto header = alloc.emplace<ModuleHeaderSyntax>(SyntaxKind::ModuleHeader,
118					token(TokenKind::ModuleKeyword, "", false, true), Token(),
119					token(TokenKind::Identifier, RTLIL::escape_id(module->name.str()), true),
120					*alloc.emplace<SyntaxList<PackageImportDeclarationSyntax>>(nullptr),
121					nullptr, // parameters: todo
122					alloc.emplace<AnsiPortListSyntax>(token(TokenKind::OpenParenthesis),
123							*alloc.emplace<SeparatedSyntaxList<MemberSyntax>>(alloc, port_list.copy(target)),
124							token(TokenKind::CloseParenthesis)),
125					token(TokenKind::Semicolon));
126	
127			SmallVector<TokenOrSyntax, 2> attrs_spec;
128			SmallVector<AttributeInstanceSyntax *, 2> attrs;
129			attrs_spec.push_back(alloc.emplace<AttributeSpecSyntax>(
130					token(TokenKind::Identifier, "blackbox", true), nullptr));
131			attrs.push_back(alloc.emplace<AttributeInstanceSyntax>(token(TokenKind::OpenParenthesis),
132					token(TokenKind::Star),
133					*alloc.emplace<SeparatedSyntaxList<AttributeSpecSyntax>>(alloc, attrs_spec.copy(target)),
134					token(TokenKind::Star, "", true), token(TokenKind::CloseParenthesis)));
135	
136			auto syntax = alloc.emplace<ModuleDeclarationSyntax>(SyntaxKind::ModuleDeclaration,
137					*alloc.emplace<SyntaxList<AttributeInstanceSyntax>>(alloc, attrs.copy(target)), *header,
138					*alloc.emplace<SyntaxList<MemberSyntax>>(alloc, std::span<const TokenOrSyntax>{}),
139					token(TokenKind::EndModuleKeyword, "", false, true), nullptr);
140	
141			decls.push_back(syntax);
142		}
143	
144		auto unit_syntax = alloc.emplace<CompilationUnitSyntax>(
145				*target.emplace<SyntaxList<MemberSyntax>>(alloc, decls.copy(target)),
146				token(TokenKind::EndOfFile, "", false, false));
147		auto tree = std::shared_ptr<SyntaxTree>(new SyntaxTree(
148				unit_syntax, mgr, std::move(alloc), &target.getDefaultLibrary(), nullptr));
149		tree->isLibraryUnit = true;
150		target.addSyntaxTree(tree);
151	}
152	
153	bool is_decl_empty_module(const slang::syntax::SyntaxNode &syntax)
154	{
155		using namespace slang::syntax;
156	
157		if (syntax.kind != SyntaxKind::ModuleDeclaration)
158			return false;
159	
160		for (auto member : syntax.as<ModuleDeclarationSyntax>().members) {
161			switch (member->kind) {
162			case SyntaxKind::TypedefDeclaration:
163			case SyntaxKind::ForwardTypedefDeclaration:
164			case SyntaxKind::ParameterDeclaration:
165			case SyntaxKind::TypeParameterDeclaration:
166			case SyntaxKind::PortDeclaration:
167			case SyntaxKind::ImplicitAnsiPort:
168			case SyntaxKind::ExplicitAnsiPort:
169			case SyntaxKind::TimeUnitsDeclaration:
170			case SyntaxKind::FunctionDeclaration:
171			case SyntaxKind::DefParam:
172			case SyntaxKind::NetAlias:                  break;
173	
174			default: return false;
175			}
176		}
177	
178		return true;
179	}
180	
181	void export_blackbox_to_rtlil(
182			NetlistContext &netlist, const ast::InstanceSymbol &inst, RTLIL::Design *target)
183	{
184		using namespace slang::ast;
185		using namespace slang::syntax;
186	
187		RTLIL::IdString name = RTLIL::escape_id(std::string{inst.body.name});
188	
189		if (target->module(name)) {
190			// Module already exists on the RLTIL side -- nothing to do
191			return;
192		}
193	
194		for (auto instance : netlist.compilation.getRoot().topInstances) {
195			if (!instance->name.compare(inst.name)) {
196				// A top module with the same name will be added later, nothing to do
197				return;
198			}
199		}
200	
201		RTLIL::Module *mod = target->addModule(name);
202		mod->set_bool_attribute(ID(blackbox), true);
203		transfer_attrs<const ast::Symbol>(netlist, (ast::Symbol &)inst.getDefinition(), mod);
204	
205		inst.body.visit(ast::makeVisitor(
206				[&](auto &, const ast::PortSymbol &port) {
207					if (!port.getSyntax() || !port.getType().isFixedSize() || !port.internalSymbol ||
208							!port.internalSymbol->getDeclaredType()) {
209						inst.body.addDiag(diag::BboxExportPortWidths, port.location);
210					} else {
211						const DeclaredType *dt = port.internalSymbol->getDeclaredType();
212						const SyntaxNode &syntax = *dt->getTypeSyntax();
213						const SyntaxList<VariableDimensionSyntax> *dims = nullptr;
214						bool rejected = false;
215	
216						if (syntax.kind == SyntaxKind::ImplicitType) {
217							auto &impl_type = syntax.as<ImplicitTypeSyntax>();
218							dims = &impl_type.dimensions;
219						} else if (IntegerTypeSyntax::isKind(syntax.kind)) {
220							auto &int_type = syntax.as<IntegerTypeSyntax>();
221							dims = &int_type.dimensions;
222						} else {
223							inst.body.addDiag(diag::BboxExportPortWidths, port.location);
224							rejected = true;
225						}
226	
227						if (dims) {
228							for (auto dim : *dims) {
229								if (!dim->specifier ||
230										dim->specifier->kind != SyntaxKind::RangeDimensionSpecifier) {
231									inst.body.addDiag(diag::BboxExportPortWidths, port.location);
232									break;
233								}
234								auto &sel =
235										dim->specifier->as<RangeDimensionSpecifierSyntax>().selector;
236								if (!RangeSelectSyntax::isKind(sel->kind) ||
237										!LiteralExpressionSyntax::isKind(
238												sel->as<RangeSelectSyntax>().left->kind) ||
239										!LiteralExpressionSyntax::isKind(
240												sel->as<RangeSelectSyntax>().right->kind)) {
241									inst.body.addDiag(diag::BboxExportPortWidths, port.location);
242									rejected = true;
243									break;
244								}
245							}
246						}
247	
248						if (!rejected && dt->getDimensionSyntax()) {
249							for (auto dim : *dt->getDimensionSyntax()) {
250								if (!dim->specifier ||
251										dim->specifier->kind != SyntaxKind::RangeDimensionSpecifier) {
252									inst.body.addDiag(diag::BboxExportPortWidths, port.location);
253									break;
254								}
255								auto &sel =
256										dim->specifier->as<RangeDimensionSpecifierSyntax>().selector;
257	
258								if (RangeSelectSyntax::isKind(sel->kind)) {
259									auto &range = sel->as<RangeSelectSyntax>();
260									if (!LiteralExpressionSyntax::isKind(range.left->kind) ||
261											!LiteralExpressionSyntax::isKind(range.right->kind)) {
262										inst.body.addDiag(diag::BboxExportPortWidths, port.location);
263										break;
264									}
265								} else if (BitSelectSyntax::isKind(sel->kind)) {
266									auto &bit = sel->as<BitSelectSyntax>();
267									if (!LiteralExpressionSyntax::isKind(bit.expr->kind)) {
268										inst.body.addDiag(diag::BboxExportPortWidths, port.location);
269										break;
270									}
271								} else {
272									inst.body.addDiag(diag::BboxExportPortWidths, port.location);
273									break;
274								}
275							}
276						}
277					}
278	
279					RTLIL::Wire *wire = mod->addWire(RTLIL::escape_id(std::string{port.name}),
280							port.getType().getBitstreamWidth());
281					transfer_attrs<const ast::Symbol>(netlist, port, wire);
282	
283					switch (port.direction) {
284					case ast::ArgumentDirection::In:  wire->port_input = true; break;
285					case ast::ArgumentDirection::Out: wire->port_output = true; break;
286					case ast::ArgumentDirection::InOut:
287						wire->port_input = true;
288						wire->port_output = true;
289						break;
290					default:
291						auto &diag = inst.body.addDiag(diag::UnsupportedPortDirection, port.location);
292						diag << ast::toString(port.direction);
293						break;
294					}
295	
296					mod->ports.push_back(wire->name);
297					wire->port_id = mod->ports.size();
298				},
299				[&](auto &, const ast::ParameterSymbol &param) {
300					mod->avail_parameters(RTLIL::escape_id(std::string{param.name}));
301				},
302				[&](auto &, const ast::InstanceSymbol &) {}));
303	}
304	
305	}; // namespace slang_frontend
