3197	{
3198		if (sym.cellDefine)
3199			return true;
3200	
3201		if (settings.blackboxed_modules.contains(sym.name))
3202			return true;
3203	
3204		for (auto attr : sym.getParentScope()->getCompilation().getAttributes(sym)) {
3205			if (attr->name == "blackbox"sv && !attr->getValue().isFalse()) {
3206				if (why_blackbox) {
3207					auto &note = why_blackbox->addNote(diag::NoteModuleBlackboxBecauseAttribute,
3208														attr->location);
3209					note << sym.name;
3210				}
3211				return true;
3212			}
3213		}
3214	
3215		if (settings.empty_blackboxes.value_or(false)) {
3216			if (why_blackbox) {
3217				auto &note = why_blackbox->addNote(diag::NoteModuleBlackboxBecauseEmpty, sym.location);
3218				note << sym.name;
