3225	
3226	bool NetlistContext::should_dissolve(const ast::InstanceSymbol &sym, slang::Diagnostic *why_not_dissolved)
3227	{
3228		// blackboxes are never dissolved
3229		if (sym.isModule() && is_blackbox(sym.body.getDefinition())) {
3230			if (why_not_dissolved) {
3231				auto &note = why_not_dissolved->addNote(diag::NoteModuleNotDissolvedBecauseBlackbox, sym.location);
3232				note << sym.body.name;
3233				// insert note about blackbox reason
3234				is_blackbox(sym.body.getDefinition(), why_not_dissolved);
3235			}
3236			return false;
3237		}
3238	
3239		// interfaces are always dissolved
3240		if (sym.isInterface())
3241			return true;
3242	
3243		if (sym.isModule()) {
3244			for (auto *conn : sym.getPortConnections()) {
3245				if (conn->port.kind == ast::SymbolKind::Port) {
3246					auto &port = conn->port.as<ast::PortSymbol>();
3247					if (port.direction != ast::ArgumentDirection::InOut)
3248						continue;
3249					if (why_not_dissolved) {
3250						auto &note = why_not_dissolved->addNote(diag::NoteModuleNotDissolvedBecauseInOut, port.location);
3251						note << sym.body.name;
3252					}
3253					return false;
3254				}
3255				if (conn->port.kind == ast::SymbolKind::MultiPort) {
3256					auto &port = conn->port.as<ast::MultiPortSymbol>();
3257					if (port.direction != ast::ArgumentDirection::InOut)
3258						continue;
3259					if (why_not_dissolved) {
3260						auto &note = why_not_dissolved->addNote(diag::NoteModuleNotDissolvedBecauseInOut, port.location);
3261						note << sym.body.name;
3262					}
3263					return false;
3264				}
3265			}
3266		}
3267	
3268		// the rest depends on the hierarchy mode
3269		switch (settings.hierarchy_mode()) {
3270		case SynthesisSettings::NONE:
3271			return true;
3272		case SynthesisSettings::BEST_EFFORT: {
3273			for (auto *conn : sym.getPortConnections()) {
3274				switch (conn->port.kind) {
3275				case ast::SymbolKind::Port:
3276				case ast::SymbolKind::MultiPort:
