void finalize_special_nets(NetlistContext &netlist)
{
	for (auto symbol : netlist.special_net_symbols) {
		for (auto bit : VariableBits(Variable::from_symbol(symbol))) {
			switch (symbol->netType.netKind) {
			case ast::NetType::WAnd:
